const xml = $json.data || $json.body || '';
const infoPages = [];
const catalogPages = [];
const matches = typeof xml === 'string' ? xml.match(/<loc>(.*?)<\/loc>/g) : null;

const infoRegex = /(iletisim|contact|ulasin|about|hakkimizda|biz-kimiz|kurumsal|adres|phone|tel)/i;
const catalogRegex = /(urun|product|kategori|category|shop|hizmet|servis|portfolio|item|store|p-)/i;

if (matches) {
  for (let match of matches) {
    let u = match.replace('<loc>', '').replace('</loc>', '').trim();
    if (infoRegex.test(u) || u === $node["Process Store One-by-One"].json.website) {
      infoPages.push(u);
    } else if (catalogRegex.test(u)) {
      catalogPages.push(u);
    }
  }
}

const website = $node["Process Store One-by-One"].json.website || '';
if (infoPages.length === 0 && website) {
  infoPages.push(website);
}
if (catalogPages.length === 0 && website) {
  catalogPages.push(website);
}

return {
  website: website,
  store_name: $node["Process Store One-by-One"].json.company_name,
  infoPages: infoPages.slice(0, 5),
  catalogPages: catalogPages.slice(0, 10)
};

const cleanHtmlForAI = (html) => {
  if (!html || typeof html !== 'string') return '';

  let cleaned = html
    .replace(/<head[^>]*>[\s\S]*?<\/head>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<svg[^>]*>[\s\S]*?<\/svg>/gi, '')
    .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
    .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '')
    .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
    .replace(/<iframe[^>]*>[\s\S]*?<\/iframe>/gi, '')
    .replace(/<noscript[^>]*>[\s\S]*?<\/noscript>/gi, '')
    .replace(/<!--[\s\S]*?-->/gi, '');

  cleaned = cleaned
    .replace(/\s(id|class|data-[a-z0-9\-]+|aria-[a-z0-9\-]+|style|onclick|target|rel|width|height|loading|onerror|tabindex|role)="[^"]*"/gi, '')
    .replace(/\s(id|class|data-[a-z0-9\-]+|aria-[a-z0-9\-]+|style|onclick|target|rel|width|height|loading|onerror|tabindex|role)='[^']*'/gi, '');

  cleaned = cleaned.replace(/\s+/g, ' ').trim();

  if (cleaned.length > 25000) {
    cleaned = cleaned.substring(0, 25000) + '... [TRUNCATED]';
  }

  return cleaned;
};

let corporate_html = '';
let catalog_html = '';
let store_name = '';
let website = '';

try {
  corporate_html = cleanHtmlForAI($node["Fetch Corporate Info HTML"].json.data || '');
} catch (e) {}

try {
  catalog_html = cleanHtmlForAI($node["Fetch Catalog List HTML"].json.data || '');
} catch (e) {}

try {
  store_name = $node["Smart Sitemap Separator"].json.store_name || '';
  website = $node["Smart Sitemap Separator"].json.website || '';
} catch (e) {}

return {
  store_name,
  website,
  corporate_html,
  catalog_html,
  html_fetched: !!(corporate_html || catalog_html)
};

