const rawContent = $('Unified AI Store Brain').first().json.message.content || "";

// Bulletproof JSON extractor: extract everything between the first '{' and the last '}'
let cleanContent = "";
const firstBrace = rawContent.indexOf("{");
const lastBrace = rawContent.lastIndexOf("}");
if (firstBrace !== -1 && lastBrace !== -1) {
  cleanContent = rawContent.substring(firstBrace, lastBrace + 1).trim();
} else {
  cleanContent = rawContent.trim();
}

const parsed = JSON.parse(cleanContent);
const products = parsed.products || [];

let store_id = "";
try {
  store_id = $('Check If Store Exists').first().json.id;
} catch (e) {}

if (!store_id) {
  try {
    store_id = $('Upsert Storefront Metadata').first().json.id;
  } catch (e) {}
}
if (!store_id) {
  try {
    store_id = $('Update Storefront Metadata').first().json.id;
  } catch (e) {}
}

return products.map(p => ({
  json: {
    store_id: store_id,
    name: p.name || "",
    category: p.category || "",
    image_url: p.image_url || "",
    description: p.description || "",
    price: Number(p.price) || 0
  }
}));
